package com.ichi2.anki.model

import com.ichi2.libanki.Config
import org.junit.Test
import org.junit.runner.RunWith
import org.mockito.Mockito.mock
import org.robolectric.RobolectricTestRunner
import org.mockito.kotlin.any
import org.mockito.kotlin.verify
import org.mockito.kotlin.eq

@RunWith(RobolectricTestRunner::class)
class SortTypeTest {

    @Test
    fun saves_cards_mode_sort_type_correctly() {
        val config = mock(Config::class.java)
        val preferences = android.content.SharedPreferencesMock()

        // Test CARDS mode
        SortType.CREATED_TIME.save(config, preferences, CardsOrNotes.CARDS, true)

        verify(config).set(eq("sortType"), eq("noteCrt"))
        verify(config).set(eq("sortBackwards"), eq(false))
    }

    @Test
    fun saves_notes_mode_sort_type_correctly() {
        val config = mock(Config::class.java)
        val preferences = android.content.SharedPreferencesMock()

        // Test NOTES mode
        SortType.CREATED_TIME.save(config, preferences, CardsOrNotes.NOTES, true)

        verify(config).set(eq("noteSortType"), eq("noteCrt"))
        verify(config).set(eq("browserNoteSortBackwards"), eq(false))
    }

    @Test
    fun saves_cards_mode_with_reverse_order() {
        val config = mock(Config::class.java)
        val preferences = android.content.SharedPreferencesMock()

        // Test CARDS mode with reverse order
        SortType.CREATED_TIME.save(config, preferences, CardsOrNotes.CARDS, false)

        verify(config).set(eq("sortType"), eq("noteCrt"))
        verify(config).set(eq("sortBackwards"), eq(true))
    }

    @Test
    fun saves_notes_mode_with_reverse_order() {
        val config = mock(Config::class.java)
        val preferences = android.content.SharedPreferencesMock()

        // Test NOTES mode with reverse order
        SortType.CREATED_TIME.save(config, preferences, CardsOrNotes.NOTES, false)

        verify(config).set(eq("noteSortType"), eq("noteCrt"))
        verify(config).set(eq("browserNoteSortBackwards"), eq(true))
    }
}"}

