 * Test to verify the display order fix for notes
 *
 *  This test verifies that:
 *  1. Sort orders are properly saved for both CARDS and NOTES modes
 *  2. Sort orders are properly loaded for both CARDS and NOTES modes
 *  3. Changing sort order in NOTES mode preserves the setting
 */

package com.ichi2.anki

import com.ichi2.anki.model.CardsOrNotes
import com.ichi2.anki.model.CardsOrNotes.CARDS
import com.ichi2.anki.model.CardsOrNotes.NOTES
import com.ichi2.anki.model.SortType
import org.junit.Assert.assertEquals
import org.junit.Test
import org.junit.runner.RunWith
import org.robolectric.RobolectricTestRunner

@RunWith(RobolectricTestRunner::class)
class CardBrowserNotesOrderTest {

    /**
     * Test that SortType.fromCol correctly loads the sort type for CARDS mode
     */
    @Test
    fun testSortTypeFromColForCards() {
        val config = com.ichi2.libanki.Config(
            net.ankiweb.rsdroid.Backend(
                java.io.File("."),
                null,
                false
            )
        )
        val preferences = com.ichi2.anki.preferences.sharedPrefs(
            com.ichi2.anki.AnkiDroidApp.getInstance()
        )

        // Set up config for CARDS mode
        config.set("sortType", "noteCrt")

        val sortType = SortType.fromCol(config, preferences, CARDS)
        assertEquals(SortType.CREATED_TIME, sortType)
    }

    /**
     * Test that SortType.fromCol correctly loads the sort type for NOTES mode
     */
    @Test
    fun testSortTypeFromColForNotes() {
        val config = com.ichi2.libanki.Config(
            net.ankiweb.rsdroid.Backend(
                java.io.File("."),
                null,
                false
            )
        )
        val preferences = com.ichi2.anki.preferences.sharedPrefs(
            com.ichi2.anki.AnkiDroidApp.getInstance()
        )

        // Set up config for NOTES mode
        config.set("noteSortType", "noteMod")

        val sortType = SortType.fromCol(config, preferences, NOTES)
        assertEquals(SortType.NOTE_MODIFICATION_TIME, sortType)
    }
}"}

